PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?port ?portName ?provided ?required WHERE {
  <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Project%2520Systems%2520Engineering::01%2520Components::Operational::TMT%2520Observatory%2520System::Conceptual%2520Design::Executive%2520Software> vocab:Element_ownedElement ?port .
  ?port rdf:type vocab:port .
  ?port vocab:NamedElement_name ?portName .
